import React, { useState, useEffect } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import { 
  ArrowLeft, 
  Star, 
  Calendar, 
  Clock, 
  Film, 
  Heart, 
  Share2,
  StarIcon
} from 'lucide-react';
import { getMovieDetails } from '../services/movieService';

const MovieDetailsPage = () => {
  const { movieId } = useParams();
  const navigate = useNavigate();

  const [movie, setMovie] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [userRating, setUserRating] = useState(0);
  const [hoverRating, setHoverRating] = useState(0);

  useEffect(() => {
    const fetchMovieDetails = async () => {
      if (!movieId) {
        setError('No movie ID provided');
        setLoading(false);
        return;
      }

      try {
        setLoading(true);
        console.log('Fetching details for movie:', movieId);

        const movieData = await getMovieDetails(movieId);
        console.log('Movie data received:', movieData);

        setMovie(movieData);
        setError(null);
      } catch (err) {
        console.error('Error fetching movie details:', err);
        setError(err.message || 'Failed to load movie details');
      } finally {
        setLoading(false);
      }
    };

    fetchMovieDetails();
  }, [movieId]);

  const handleBack = () => {
    navigate('/movies');
  };

  const formatRating = (rating) => {
    if (!rating) return '0.0';
    return Number(rating).toFixed(1);
  };

  const formatYear = (dateString) => {
    if (!dateString) return '';
    try {
      return new Date(dateString).getFullYear();
    } catch {
      return dateString;
    }
  };

  const formatGenres = (genres) => {
    if (!genres) return '';
    if (Array.isArray(genres)) {
      return genres.join(' • ');
    }
    return String(genres);
  };

  const RatingStars = ({ rating, interactive = false, onRate }) => {
    const stars = [];
    const displayRating = interactive ? (hoverRating || userRating) : rating;

    for (let i = 1; i <= 5; i++) {
      stars.push(
        <button
          key={i}
          className={`${interactive ? 'cursor-pointer hover:scale-110' : 'cursor-default'} transition-all duration-200`}
          onMouseEnter={() => interactive && setHoverRating(i)}
          onMouseLeave={() => interactive && setHoverRating(0)}
          onClick={() => interactive && onRate && onRate(i)}
          disabled={!interactive}
        >
          <Star
            className={`w-6 h-6 ${
              i <= displayRating 
                ? 'fill-yellow-400 text-yellow-400' 
                : 'text-gray-300'
            } transition-colors duration-200`}
          />
        </button>
      );
    }
    return <div className="flex space-x-1">{stars}</div>;
  };

  const handleRateMovie = (rating) => {
    setUserRating(rating);
    console.log('Rating movie:', movieId, 'with rating:', rating);
    // TODO: Implement actual rating API call
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600 mx-auto"></div>
          <p className="mt-4 text-gray-600">Loading movie details...</p>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center max-w-md mx-auto p-6">
          <Film className="w-16 h-16 text-gray-400 mx-auto mb-4" />
          <h2 className="text-2xl font-bold text-gray-800 mb-2">Movie Not Found</h2>
          <p className="text-gray-600 mb-6">{error}</p>
          <button
            onClick={handleBack}
            className="bg-blue-600 text-white px-6 py-2 rounded-lg hover:bg-blue-700 transition-colors"
          >
            Back to Movies
          </button>
        </div>
      </div>
    );
  }

  if (!movie) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center">
          <p className="text-gray-600">No movie data available</p>
        </div>
      </div>
    );
  }

  const {
    title,
    description,
    release_date,
    genres,
    avg_rating,
    rating_count,
    poster_url,
    similar_movies = []
  } = movie;

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Header */}
      <div className="bg-white shadow-sm sticky top-0 z-10">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4">
          <button
            onClick={handleBack}
            className="flex items-center text-gray-600 hover:text-gray-800 transition-colors"
          >
            <ArrowLeft className="w-5 h-5 mr-2" />
            Back
          </button>
        </div>
      </div>

      {/* Movie Details */}
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <div className="bg-white rounded-lg shadow-lg overflow-hidden">
          <div className="md:flex">
            {/* Movie Poster */}
            <div className="md:w-1/3 lg:w-1/4">
              {poster_url ? (
                <img
                  src={poster_url}
                  alt={`${title} poster`}
                  className="w-full h-auto object-cover"
                />
              ) : (
                <div className="w-full h-96 bg-gray-200 flex items-center justify-center">
                  <Film className="w-24 h-24 text-gray-400" />
                </div>
              )}
            </div>

            {/* Movie Info */}
            <div className="md:w-2/3 lg:w-3/4 p-8">
              {/* Title and Rating */}
              <div className="mb-6">
                <div className="flex items-start justify-between mb-4">
                  <div>
                    <h1 className="text-4xl font-bold text-gray-900 mb-2">{title}</h1>
                    <div className="flex items-center space-x-4 text-gray-600">
                      {release_date && (
                        <div className="flex items-center">
                          <Calendar className="w-4 h-4 mr-1" />
                          {formatYear(release_date)}
                        </div>
                      )}
                      {genres && (
                        <div className="text-blue-600 font-medium">
                          {formatGenres(genres)}
                        </div>
                      )}
                    </div>
                  </div>

                  {avg_rating && (
                    <div className="text-right">
                      <div className="flex items-center justify-end mb-1">
                        <Star className="w-6 h-6 fill-yellow-400 text-yellow-400 mr-1" />
                        <span className="text-3xl font-bold text-gray-900">
                          {formatRating(avg_rating)}
                        </span>
                      </div>
                      <p className="text-sm text-gray-500">
                        {rating_count || 0} rating{rating_count !== 1 ? 's' : ''}
                      </p>
                    </div>
                  )}
                </div>

                {/* User Rating */}
                <div className="bg-gray-50 rounded-lg p-4 mb-6">
                  <h3 className="text-lg font-semibold text-gray-900 mb-3">Your Rating</h3>
                  <div className="flex items-center space-x-4">
                    <RatingStars 
                      rating={userRating} 
                      interactive={true} 
                      onRate={handleRateMovie}
                    />
                    <span className="text-gray-600">
                      {userRating > 0 ? `${userRating}/5` : 'Not rated'}
                    </span>
                  </div>
                </div>
              </div>

              {/* Description */}
              {description && (
                <div className="mb-8">
                  <h3 className="text-xl font-semibold text-gray-900 mb-3">Plot</h3>
                  <p className="text-gray-700 leading-relaxed text-lg">{description}</p>
                </div>
              )}

              {/* Action Buttons */}
              <div className="flex flex-wrap gap-4">
                <button className="bg-blue-600 text-white px-6 py-3 rounded-lg hover:bg-blue-700 transition-colors flex items-center">
                  <Star className="w-5 h-5 mr-2" />
                  Rate Movie
                </button>
                <button className="bg-gray-200 text-gray-800 px-6 py-3 rounded-lg hover:bg-gray-300 transition-colors flex items-center">
                  <Heart className="w-5 h-5 mr-2" />
                  Add to Watchlist
                </button>
                <button className="bg-gray-200 text-gray-800 px-6 py-3 rounded-lg hover:bg-gray-300 transition-colors flex items-center">
                  <Share2 className="w-5 h-5 mr-2" />
                  Share
                </button>
              </div>
            </div>
          </div>
        </div>

        {/* Similar Movies */}
        {similar_movies && similar_movies.length > 0 && (
          <div className="mt-12">
            <div className="flex items-center justify-between mb-6">
              <h2 className="text-2xl font-bold text-gray-900">Similar Movies</h2>
              <Link 
                to="/movies"
                className="text-blue-600 hover:text-blue-700 font-medium"
              >
                View All
              </Link>
            </div>

            <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-6">
              {similar_movies.slice(0, 10).map((similarMovie, index) => (
                <div key={similarMovie.id || index} className="bg-white rounded-lg shadow-md overflow-hidden hover:shadow-lg transition-shadow">
                  <Link to={`/movies/${similarMovie.id}`}>
                    {similarMovie.poster_url ? (
                      <img
                        src={similarMovie.poster_url}
                        alt={`${similarMovie.title} poster`}
                        className="w-full h-64 object-cover"
                      />
                    ) : (
                      <div className="w-full h-64 bg-gray-200 flex items-center justify-center">
                        <Film className="w-12 h-12 text-gray-400" />
                      </div>
                    )}
                    <div className="p-4">
                      <h3 className="font-semibold text-gray-900 mb-2 line-clamp-2">
                        {similarMovie.title}
                      </h3>
                      <div className="flex items-center justify-between text-sm">
                        <span className="text-gray-600">
                          {formatYear(similarMovie.release_date)}
                        </span>
                        {similarMovie.avg_rating && (
                          <div className="flex items-center text-yellow-600">
                            <Star className="w-4 h-4 fill-current mr-1" />
                            {formatRating(similarMovie.avg_rating)}
                          </div>
                        )}
                      </div>
                    </div>
                  </Link>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Back to Movies */}
        <div className="mt-12 text-center">
          <Link
            to="/movies"
            className="inline-flex items-center text-blue-600 hover:text-blue-700 font-medium"
          >
            <ArrowLeft className="w-5 h-5 mr-2" />
            Back to Movies
          </Link>
        </div>
      </div>
    </div>
  );
};

export default MovieDetailsPage;
